+fn parse_id_list(raw: &str) -> Result<Vec<u64>, AppError> {
+    let mut ids = Vec::new();
+    for part in raw.split(',') {
+        let token = part.trim();
+        if token.is_empty() {
+            continue;
+        }
+        match token.parse::<u64>() {
+            Ok(value) => ids.push(value),
+            Err(_) => {
+                return Err(AppError::bad_request(format!(
+                    "unable to parse agent id '{token}'"
+                )));
+            }
+        }
+    }
+    Ok(ids)
+}
